import{_ as l,o as e,c as i,a2 as h}from"./chunks/framework.BRk9mohw.js";const d=JSON.parse('{"title":"聊天渠道","description":"","frontmatter":{},"headers":[],"relativePath":"channels/index.md","filePath":"channels/index.md"}'),t={name:"channels/index.md"};function n(s,a,r,o,c,m){return e(),i("div",null,[...a[0]||(a[0]=[h('<h1 id="聊天渠道" tabindex="-1">聊天渠道 <a class="header-anchor" href="#聊天渠道" aria-label="Permalink to &quot;聊天渠道&quot;">​</a></h1><h1 id="聊天渠道-1" tabindex="-1">聊天渠道 <a class="header-anchor" href="#聊天渠道-1" aria-label="Permalink to &quot;聊天渠道&quot;">​</a></h1><p>OpenClaw 可以通过您正在使用的任何聊天应用与您对话。每个渠道都通过网关进行连接。 所有渠道都支持文本；媒体和表情反应因渠道而异。</p><h2 id="支持的渠道" tabindex="-1">支持的渠道 <a class="header-anchor" href="#支持的渠道" aria-label="Permalink to &quot;支持的渠道&quot;">​</a></h2><ul><li><a href="/channels/bluebubbles.html">BlueBubbles</a> — <strong>推荐用于 iMessage</strong>；使用 BlueBubbles macOS 服务器 REST API，支持完整功能（编辑、撤回、效果、表情反应、群组管理 — macOS 26 Tahoe 上编辑功能目前不可用）。</li><li><a href="/channels/discord.html">Discord</a> — Discord 机器人 API + Gateway；支持服务器、频道和私信。</li><li><a href="/channels/feishu.html">Feishu</a> — 飞书/钉钉机器人 via WebSocket（插件，需单独安装）。</li><li><a href="/channels/googlechat.html">Google Chat</a> — Google Chat API 应用 via HTTP webhook。</li><li><a href="/channels/imessage.html">iMessage（传统）</a> — 传统 macOS 集成 via imsg CLI（已弃用，新设置请使用 BlueBubbles）。</li><li><a href="/channels/irc.html">IRC</a> — 经典 IRC 服务器；频道和私信，支持配对/白名单控制。</li><li><a href="/channels/line.html">LINE</a> — LINE 消息 API 机器人（插件，需单独安装）。</li><li><a href="/channels/matrix.html">Matrix</a> — Matrix 协议（插件，需单独安装）。</li><li><a href="/channels/mattermost.html">Mattermost</a> — 机器人 API + WebSocket；频道、群组、私信（插件，需单独安装）。</li><li><a href="/channels/msteams.html">Microsoft Teams</a> — 机器人框架；企业支持（插件，需单独安装）。</li><li><a href="/channels/nextcloud-talk.html">Nextcloud Talk</a> — 自托管聊天 via Nextcloud Talk（插件，需单独安装）。</li><li><a href="/channels/nostr.html">Nostr</a> — 去中心化私信 via NIP-04（插件，需单独安装）。</li><li><a href="/channels/signal.html">Signal</a> — signal-cli；注重隐私。</li><li><a href="/channels/synology-chat.html">Synology Chat</a> — 群晖 NAS Chat via 出站+入站 webhook（插件，需单独安装）。</li><li><a href="/channels/slack.html">Slack</a> — Bolt SDK；工作区应用。</li><li><a href="/channels/telegram.html">Telegram</a> — 机器人 API via grammY；支持群组。</li><li><a href="/channels/tlon.html">Tlon</a> — 基于 Urbit 的 messenger（插件，需单独安装）。</li><li><a href="/channels/twitch.html">Twitch</a> — Twitch 聊天 via IRC 连接（插件，需单独安装）。</li><li><a href="/web/webchat.html">WebChat</a> — 网关 WebChat UI via WebSocket。</li><li><a href="/channels/whatsapp.html">WhatsApp</a> — 最流行的聊天应用；使用 Baileys，需要二维码配对。</li><li><a href="/channels/zalo.html">Zalo</a> — Zalo 机器人 API；越南流行的 messenger（插件，需单独安装）。</li><li><a href="/channels/zalouser.html">Zalo 个人</a> — Zalo 个人账户 via 二维码登录（插件，需单独安装）。</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>渠道可以同时运行；配置多个渠道后，OpenClaw 会根据聊天进行路由。</li><li>最快的设置通常是 <strong>Telegram</strong>（简单的机器人令牌）。WhatsApp 需要二维码配对，并在磁盘上存储更多状态。</li><li>群组行为因渠道而异；请参阅<a href="/channels/groups.html">群组</a>。</li><li>私信配对和白名单强制执行以确保安全；请参阅<a href="/gateway/security.html">安全</a>。</li><li>故障排除：<a href="/channels/troubleshooting.html">渠道故障排除</a>。</li><li>模型提供商文档单独提供；请参阅<a href="/providers/models.html">模型提供商</a>。</li></ul>',7)])])}const u=l(t,[["render",n]]);export{d as __pageData,u as default};
